/**
 * Defines the possible abi call signatures.
 */
export type BoxContractSignatures = keyof BoxContractTypes['methods']
/**
 * Defines the possible abi call signatures for methods that return a non-void value.
 */
export type BoxContractNonVoidMethodSignatures = keyof BoxContractTypes['methods'] extends infer T ? T extends keyof BoxContractTypes['methods'] ? MethodReturn<T> extends void ? never : T  : never : never
/**
 * Defines an object containing all relevant parameters for a single call to the contract.
 */
export type CallParams<TArgs> = Expand<
  Omit<AppClientMethodCallParams, 'method' | 'args' | 'onComplete'> &
    {
      /** The args for the ABI method call, either as an ordered array or an object */
      args: Expand<TArgs>
    }
>
/**
 * Maps a method signature from the BoxContract smart contract to the method's arguments in either tuple or struct form
 */
export type MethodArgs<TSignature extends BoxContractSignatures> = BoxContractTypes['methods'][TSignature]['argsObj' | 'argsTuple']
/**
 * Maps a method signature from the BoxContract smart contract to the method's return type
 */
export type MethodReturn<TSignature extends BoxContractSignatures> = BoxContractTypes['methods'][TSignature]['returns']

/**
 * Defines the shape of the keyed box state of the application.
 */
export type BoxKeysState = BoxContractTypes['state']['box']['keys']


/**
 * Defines supported create method params for this smart contract
 */
export type BoxContractCreateCallParams =
  | Expand<AppClientBareCallParams & {method?: never} & { onComplete?: OnApplicationComplete.NoOp } & CreateSchema>
/**
 * Defines arguments required for the deploy method.
 */
export type BoxContractDeployParams = Expand<Omit<AppFactoryDeployParams, 'createParams' | 'updateParams' | 'deleteParams'> & {
  /**
   * Create transaction parameters to use if a create needs to be issued as part of deployment; use `method` to define ABI call (if available) or leave out for a bare call (if available)
   */
  createParams?: BoxContractCreateCallParams
}>


